import { describe, expect, it, vi } from "vitest";
import { NotAuthenticatedError } from "./errors.js";
import { withStudioSession } from "./withStudioSession.js";
vi.mock("./activeStudioSession.js", () => ({
    readActiveStudioSession: () => null,
}));
vi.mock("./commands/openStudio.js", () => ({
    openStudio: vi.fn(),
}));
vi.mock("./agentSessionChannel.js", () => ({
    navigateStudioAndAwaitAck: vi.fn(),
}));
describe("withStudioSession", () => {
    it("throws NotAuthenticatedError when apiKey is empty", async () => {
        await expect(withStudioSession({
            apiKey: "",
            serviceUrl: "https://test.invalid",
            targetPath: "/studio/trace-plan/abc",
        })).rejects.toThrow(NotAuthenticatedError);
    });
});
